export enum ViewState {
  LOBBY = 'LOBBY',
  PORTFOLIO = 'PORTFOLIO',
  CONTACT = 'CONTACT',
  SERVICES = 'SERVICES'
}

export enum BackgroundTheme {
  CYBER = 'CYBER',
  DESERT = 'DESERT',
  CITY = 'CITY',
  JUNGLE = 'JUNGLE',
  ANTARCTICA = 'ANTARCTICA'
}

export interface CharacterConfig {
  name: string;
  role: string;
  hairColor: 'black' | 'blond';
  outfitColor: string;
  isReady: boolean;
  avatarSeed: string; // For dicebear API
}

import React, { useState, useEffect, useRef } from 'react';
import { Menu, Settings, Monitor, Users, Mail, Phone, Briefcase, Award, Upload, X, MapPin, Building2, Trees, Snowflake, Sun } from 'lucide-react';
import { ViewState, BackgroundTheme } from './types';
import { GameButton } from './components/GameButton';
import { Modal } from './components/Modal';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>(ViewState.LOBBY);
  const [backgroundTheme, setBackgroundTheme] = useState<BackgroundTheme>(BackgroundTheme.CYBER);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });

  // Drag and Drop State
  const [dragActive, setDragActive] = useState(false);
  const [files, setFiles] = useState<File[]>([]);
  const inputRef = useRef<HTMLInputElement>(null);

  // Parallax effect logic
  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      setMousePosition({
        x: (e.clientX / window.innerWidth - 0.5) * 20,
        y: (e.clientY / window.innerHeight - 0.5) * 20
      });
    };
    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  // Drag Handlers
  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      const newFiles = Array.from(e.dataTransfer.files).filter((file: File) => file.type.startsWith('image/'));
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    e.preventDefault();
    if (e.target.files && e.target.files[0]) {
      const newFiles = Array.from(e.target.files).filter((file: File) => file.type.startsWith('image/'));
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  // Render Background based on Theme
  const renderBackground = () => {
    switch (backgroundTheme) {
      case BackgroundTheme.DESERT:
        return (
          <>
            <div className="absolute inset-0 bg-gradient-to-b from-orange-500 via-amber-700 to-amber-950" />
            <div className="absolute top-20 left-1/2 -translate-x-1/2 w-96 h-96 bg-yellow-500 rounded-full blur-[100px] opacity-60" />
            <div className="absolute inset-x-0 bottom-0 h-[60vh] perspective-container opacity-40">
              <div 
                className="w-full h-full floor-grid" 
                style={{ 
                  backgroundImage: `linear-gradient(rgba(251, 191, 36, 0.4) 1px, transparent 1px), linear-gradient(90deg, rgba(251, 191, 36, 0.4) 1px, transparent 1px)` 
                }}
              />
            </div>
            {/* Heat Haze/Dust Particles */}
            <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-40 mix-blend-overlay" />
          </>
        );
      case BackgroundTheme.CITY:
        return (
          <>
            <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_center,_var(--tw-gradient-stops))] from-fuchsia-900/80 via-purple-950 to-black" />
            {/* City Lights Traffic */}
            <div className="absolute inset-0 overflow-hidden opacity-50">
               {[...Array(5)].map((_, i) => (
                 <div 
                   key={i}
                   className="absolute h-[2px] bg-cyan-400 blur-[2px] animate-traffic"
                   style={{ 
                     top: `${60 + (i * 8)}%`, 
                     left: '-10%', 
                     width: '150px',
                     animationDuration: `${2 + i}s`,
                     animationDelay: `${i * 0.5}s`
                   }} 
                 />
               ))}
                {[...Array(5)].map((_, i) => (
                 <div 
                   key={`r-${i}`}
                   className="absolute h-[2px] bg-red-500 blur-[2px] animate-traffic"
                   style={{ 
                     top: `${62 + (i * 8)}%`, 
                     left: '-10%', 
                     width: '150px',
                     animationDirection: 'reverse',
                     animationDuration: `${3 + i}s`,
                     animationDelay: `${i * 0.7}s`
                   }} 
                 />
               ))}
            </div>
            <div className="absolute inset-x-0 bottom-0 h-[60vh] perspective-container opacity-60">
              <div 
                className="w-full h-full floor-grid"
                style={{ 
                  backgroundImage: `linear-gradient(rgba(216, 180, 254, 0.5) 1px, transparent 1px), linear-gradient(90deg, rgba(168, 85, 247, 0.5) 1px, transparent 1px)` 
                }} 
              />
            </div>
          </>
        );
      case BackgroundTheme.JUNGLE:
        return (
          <>
            <div className="absolute inset-0 bg-gradient-to-b from-emerald-950 via-green-900 to-black" />
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,_var(--tw-gradient-stops))] from-green-500/10 via-transparent to-black" />

            {/* Fireflies */}
            <div className="absolute inset-0 overflow-hidden">
              {[...Array(20)].map((_, i) => (
                <div 
                  key={i}
                  className="absolute w-1.5 h-1.5 bg-yellow-300 rounded-full blur-[1px] animate-firefly"
                  style={{ 
                    top: `${Math.random() * 80}%`, 
                    left: `${Math.random() * 100}%`,
                    animationDuration: `${3 + Math.random() * 4}s`,
                    animationDelay: `${Math.random() * 2}s`
                  }} 
                />
              ))}
            </div>

            <div className="absolute inset-x-0 bottom-0 h-[60vh] perspective-container opacity-30">
              <div 
                className="w-full h-full floor-grid" 
                style={{ 
                  backgroundImage: `linear-gradient(rgba(34, 197, 94, 0.3) 1px, transparent 1px), linear-gradient(90deg, rgba(34, 197, 94, 0.3) 1px, transparent 1px)` 
                }}
              />
            </div>
          </>
        );
      case BackgroundTheme.ANTARCTICA:
        return (
          <>
            <div className="absolute inset-0 bg-gradient-to-b from-slate-900 via-cyan-900 to-slate-200" />
            {/* Snow */}
            <div className="absolute inset-0 overflow-hidden pointer-events-none">
              {[...Array(30)].map((_, i) => (
                <div 
                  key={i}
                  className="absolute w-1 h-1 bg-white rounded-full animate-snow opacity-80"
                  style={{ 
                    left: `${Math.random() * 100}%`,
                    animationDuration: `${2 + Math.random() * 3}s`,
                    animationDelay: `${Math.random() * 5}s`
                  }} 
                />
              ))}
            </div>
             <div className="absolute inset-x-0 bottom-0 h-[60vh] perspective-container opacity-50">
              <div 
                className="w-full h-full floor-grid" 
                style={{ 
                  backgroundImage: `linear-gradient(rgba(207, 250, 254, 0.4) 1px, transparent 1px), linear-gradient(90deg, rgba(207, 250, 254, 0.4) 1px, transparent 1px)` 
                }}
              />
            </div>
            <div className="absolute inset-0 bg-white/5" />
          </>
        );
      case BackgroundTheme.CYBER:
      default:
        return (
          <>
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-blue-900/80 via-slate-900 to-black" />
            <div className="absolute inset-x-0 bottom-0 h-[60vh] perspective-container opacity-40">
              <div className="w-full h-full floor-grid" />
            </div>
            <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20" />
          </>
        );
    }
  };

  return (
    <div className="relative h-screen w-screen overflow-hidden bg-slate-900 text-white select-none">

      {/* BACKGROUND LAYER */}
      <div className="absolute inset-0 z-0 transition-colors duration-1000">
        {renderBackground()}
      </div>

      {/* 3D SCENE LAYER */}
      <div 
        className="absolute inset-0 z-10 flex items-center justify-center pb-0 gap-8 transition-transform duration-100 ease-out"
        style={{ transform: `translate(${mousePosition.x * -1}px, ${mousePosition.y * -0.5}px)` }}
      >
        <div 
          className={`relative w-[90%] max-w-4xl h-[60vh] border-4 border-dashed rounded-xl flex flex-col items-center justify-center transition-all duration-300 backdrop-blur-sm overflow-hidden group cursor-pointer
          ${dragActive ? 'border-yellow-400 bg-yellow-400/10 scale-[1.02] shadow-[0_0_50px_rgba(250,204,21,0.3)]' : 'border-blue-500/30 bg-slate-900/60 hover:border-blue-400 hover:bg-slate-900/80 shadow-[0_0_30px_rgba(37,99,235,0.2)]'}`}
          onDragEnter={handleDrag}
          onDragLeave={handleDrag}
          onDragOver={handleDrag}
          onDrop={handleDrop}
          onClick={() => inputRef.current?.click()}
        >
            <input 
              ref={inputRef}
              type="file" 
              className="hidden" 
              multiple 
              accept="image/*" 
              onChange={handleChange}
            />

            {files.length === 0 ? (
              <div className="flex flex-col items-center text-slate-400 group-hover:text-white transition-colors p-8 text-center pointer-events-none">
                <div className={`p-6 rounded-full bg-slate-800/80 mb-6 transition-transform duration-500 ${dragActive ? 'scale-110 rotate-12' : 'group-hover:scale-110'}`}>
                   <Upload size={64} className={dragActive ? "text-yellow-400" : "text-blue-500"} />
                </div>
                <h2 className="text-4xl font-gaming uppercase tracking-widest mb-2 drop-shadow-md">
                  {dragActive ? "Drop Intel Here" : "Upload Assets"}
                </h2>
                <p className="text-sm font-bold tracking-wider uppercase opacity-70">
                  Drag & Drop files or Click to Browse
                </p>

                {/* Decorative lines */}
                <div className="absolute top-0 left-0 w-16 h-16 border-t-4 border-l-4 border-current opacity-50" />
                <div className="absolute bottom-0 right-0 w-16 h-16 border-b-4 border-r-4 border-current opacity-50" />
              </div>
            ) : (
              <div className="w-full h-full p-6 overflow-y-auto grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4" onClick={(e) => e.stopPropagation()}>
                 {/* Add button small */}
                 <div 
                    onClick={() => inputRef.current?.click()}
                    className="aspect-square border-2 border-dashed border-slate-500 rounded flex flex-col items-center justify-center cursor-pointer hover:border-white hover:bg-white/5 transition-colors text-slate-400 hover:text-white"
                 >
                   <Upload size={24} />
                   <span className="text-xs font-bold mt-2 uppercase">Add More</span>
                 </div>

                 {files.map((file, idx) => (
                   <div key={idx} className="relative aspect-square bg-slate-800 rounded overflow-hidden border border-slate-600 group/item">
                     <img src={URL.createObjectURL(file)} alt="preview" className="w-full h-full object-cover" />
                     <button 
                       onClick={() => removeFile(idx)}
                       className="absolute top-2 right-2 p-1 bg-red-500 text-white rounded opacity-0 group-hover/item:opacity-100 transition-opacity hover:bg-red-600"
                     >
                       <X size={16} />
                     </button>
                     <div className="absolute bottom-0 inset-x-0 bg-black/70 p-1 text-[10px] text-white truncate px-2">
                       {file.name}
                     </div>
                   </div>
                 ))}
              </div>
            )}

            {/* Corner accents for the box */}
            <div className={`absolute top-0 left-0 w-4 h-4 border-t-2 border-l-2 transition-colors ${dragActive ? 'border-yellow-400' : 'border-blue-400'}`} />
            <div className={`absolute top-0 right-0 w-4 h-4 border-t-2 border-r-2 transition-colors ${dragActive ? 'border-yellow-400' : 'border-blue-400'}`} />
            <div className={`absolute bottom-0 left-0 w-4 h-4 border-b-2 border-l-2 transition-colors ${dragActive ? 'border-yellow-400' : 'border-blue-400'}`} />
            <div className={`absolute bottom-0 right-0 w-4 h-4 border-b-2 border-r-2 transition-colors ${dragActive ? 'border-yellow-400' : 'border-blue-400'}`} />
        </div>
      </div>

      {/* UI OVERLAY LAYER */}
      <div className="absolute inset-0 z-20 pointer-events-none flex flex-col justify-between p-6 md:p-10">

        {/* HEADER: Top Bar */}
        <div className="flex justify-between items-start pointer-events-auto">
          {/* Logo / Brand */}
          <div className="flex flex-col">
            <h1 className="text-4xl md:text-6xl font-gaming italic text-white drop-shadow-[0_0_10px_rgba(59,130,246,0.8)]">
              Magnetic Marketing
            </h1>
            <span className="text-blue-400 font-bold tracking-[0.3em] text-xs md:text-sm uppercase">
              Don't Chase... ATTRACT
            </span>
          </div>

          {/* Top Right Menu */}
          <div className="flex gap-4">
            <button className="p-2 hover:bg-white/10 rounded transition-colors text-slate-300 hover:text-white">
              <Menu size={32} />
            </button>
            <button 
              onClick={() => setIsSettingsOpen(true)}
              className="p-2 hover:bg-white/10 rounded transition-colors text-slate-300 hover:text-white"
            >
              <Settings size={32} />
            </button>
          </div>
        </div>

        {/* LEFT SIDEBAR: Navigation Buttons */}
        <div className="absolute left-6 md:left-10 top-1/2 -translate-y-1/2 flex flex-col gap-4 pointer-events-auto w-48 md:w-64">
          <GameButton 
            label="Portfolio" 
            subLabel="View Our Work"
            variant="ghost" 
            onClick={() => setView(ViewState.PORTFOLIO)}
            icon={<Briefcase size={20} />}
            className="w-full !justify-start"
          />
          <GameButton 
            label="Services" 
            subLabel="What We Do"
            variant="ghost" 
            onClick={() => setView(ViewState.SERVICES)}
            icon={<Monitor size={20} />}
            className="w-full !justify-start"
          />
           <GameButton 
            label="Team" 
            subLabel="About Us"
            variant="ghost" 
            onClick={() => {}} 
            icon={<Users size={20} />}
            className="w-full !justify-start border-l-4 !border-l-yellow-400 bg-slate-800/80" // Active style simulation
          />
        </div>

        {/* RIGHT SIDEBAR: "News" or Featured */}
        <div className="absolute right-6 md:right-10 top-1/2 -translate-y-1/2 hidden lg:flex flex-col gap-4 pointer-events-auto w-64">
          <div className="bg-blue-900/60 border border-blue-500/30 p-4 rounded backdrop-blur-sm transform rotate-1 hover:rotate-0 transition-transform cursor-pointer">
            <div className="bg-red-500 text-white text-xs font-bold px-2 py-0.5 inline-block rounded mb-2 uppercase">New Season</div>
            <h3 className="font-bold text-lg leading-tight mb-1">Growth Hacking v2.0</h3>
            <p className="text-xs text-blue-200">Boost your ROI with our new automated strategies.</p>
          </div>
          <div className="bg-slate-800/60 border border-slate-600/30 p-4 rounded backdrop-blur-sm -rotate-1 hover:rotate-0 transition-transform cursor-pointer">
            <h3 className="font-bold text-lg leading-tight mb-1">Client Success</h3>
            <p className="text-xs text-slate-300">How we scaled generic-brand to 10k users.</p>
          </div>
        </div>

        {/* FOOTER: Action Bar */}
        <div className="relative w-full h-24 pointer-events-auto flex items-end justify-end">

          {/* Main Call To Action (Bottom Right) */}
          <div className="flex items-center gap-4">
             {/* "Squad" Info (Decorative) */}
            <div className="hidden md:flex flex-col items-end mr-4 text-right">
              <span className="text-xs text-slate-400 uppercase tracking-widest font-bold">Party Size</span>
              <span className="text-xl font-gaming text-white">2 / 4</span>
            </div>

            <GameButton 
              label="Neem Contact Op" 
              subLabel="Start Your Project"
              variant="primary" 
              onClick={() => setView(ViewState.CONTACT)}
              className="text-lg md:text-2xl min-w-[250px] md:min-w-[300px] h-16 md:h-20"
            />
          </div>
        </div>
      </div>

      {/* MODALS */}
      <Modal 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)}
        title="Environment Settings"
      >
        <div className="grid grid-cols-2 gap-4">
          <button 
            onClick={() => { setBackgroundTheme(BackgroundTheme.CYBER); setIsSettingsOpen(false); }}
            className={`p-4 rounded border-2 flex flex-col items-center gap-2 transition-all hover:scale-105 ${backgroundTheme === BackgroundTheme.CYBER ? 'border-blue-500 bg-blue-500/20' : 'border-slate-700 bg-slate-800 hover:border-blue-400'}`}
          >
            <div className="w-12 h-12 rounded-full bg-blue-600 flex items-center justify-center mb-2 shadow-[0_0_15px_rgba(37,99,235,0.5)]">
              <Monitor size={24} className="text-white" />
            </div>
            <span className="font-gaming text-lg tracking-wider">Cyber Lobby</span>
          </button>

          <button 
            onClick={() => { setBackgroundTheme(BackgroundTheme.DESERT); setIsSettingsOpen(false); }}
            className={`p-4 rounded border-2 flex flex-col items-center gap-2 transition-all hover:scale-105 ${backgroundTheme === BackgroundTheme.DESERT ? 'border-orange-500 bg-orange-500/20' : 'border-slate-700 bg-slate-800 hover:border-orange-400'}`}
          >
            <div className="w-12 h-12 rounded-full bg-orange-500 flex items-center justify-center mb-2 shadow-[0_0_15px_rgba(249,115,22,0.5)]">
              <Sun size={24} className="text-white" />
            </div>
            <span className="font-gaming text-lg tracking-wider">Desert Ops</span>
          </button>

          <button 
            onClick={() => { setBackgroundTheme(BackgroundTheme.CITY); setIsSettingsOpen(false); }}
            className={`p-4 rounded border-2 flex flex-col items-center gap-2 transition-all hover:scale-105 ${backgroundTheme === BackgroundTheme.CITY ? 'border-purple-500 bg-purple-500/20' : 'border-slate-700 bg-slate-800 hover:border-purple-400'}`}
          >
            <div className="w-12 h-12 rounded-full bg-purple-600 flex items-center justify-center mb-2 shadow-[0_0_15px_rgba(147,51,234,0.5)]">
              <Building2 size={24} className="text-white" />
            </div>
            <span className="font-gaming text-lg tracking-wider">Night City</span>
          </button>

          <button 
            onClick={() => { setBackgroundTheme(BackgroundTheme.JUNGLE); setIsSettingsOpen(false); }}
            className={`p-4 rounded border-2 flex flex-col items-center gap-2 transition-all hover:scale-105 ${backgroundTheme === BackgroundTheme.JUNGLE ? 'border-green-500 bg-green-500/20' : 'border-slate-700 bg-slate-800 hover:border-green-400'}`}
          >
             <div className="w-12 h-12 rounded-full bg-green-600 flex items-center justify-center mb-2 shadow-[0_0_15px_rgba(22,163,74,0.5)]">
              <Trees size={24} className="text-white" />
            </div>
            <span className="font-gaming text-lg tracking-wider">Jungle Zone</span>
          </button>

          <button 
            onClick={() => { setBackgroundTheme(BackgroundTheme.ANTARCTICA); setIsSettingsOpen(false); }}
            className={`col-span-2 p-4 rounded border-2 flex flex-col items-center gap-2 transition-all hover:scale-105 ${backgroundTheme === BackgroundTheme.ANTARCTICA ? 'border-cyan-500 bg-cyan-500/20' : 'border-slate-700 bg-slate-800 hover:border-cyan-400'}`}
          >
             <div className="w-12 h-12 rounded-full bg-cyan-400 flex items-center justify-center mb-2 shadow-[0_0_15px_rgba(34,211,238,0.5)]">
              <Snowflake size={24} className="text-white" />
            </div>
            <span className="font-gaming text-lg tracking-wider">Deep Freeze</span>
          </button>
        </div>
      </Modal>

      <Modal 
        isOpen={view === ViewState.PORTFOLIO} 
        onClose={() => setView(ViewState.LOBBY)}
        title="Mission Archive"
      >
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {[1, 2, 3, 4].map((item) => (
            <div key={item} className="bg-slate-800 border border-slate-600 p-4 rounded hover:border-blue-400 transition-colors group cursor-pointer">
              <div className="h-40 bg-slate-700 mb-4 rounded overflow-hidden relative">
                <img src={`https://picsum.photos/seed/${item + 50}/400/300`} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" alt="Project" />
                <div className="absolute inset-0 bg-blue-500/20 opacity-0 group-hover:opacity-100 transition-opacity" />
              </div>
              <h3 className="font-bold text-xl text-white mb-1">Project Alpha {item}</h3>
              <p className="text-sm text-slate-400">Branding, Web Design, SEO</p>
            </div>
          ))}
        </div>
      </Modal>

      <Modal 
        isOpen={view === ViewState.SERVICES} 
        onClose={() => setView(ViewState.LOBBY)}
        title="Loadout"
      >
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
           <div className="bg-slate-800/80 p-6 border-t-4 border-yellow-400">
             <div className="w-12 h-12 bg-yellow-400/20 flex items-center justify-center rounded mb-4 text-yellow-400">
               <Award size={24} />
             </div>
             <h3 className="text-xl font-bold text-white mb-2">Strategy</h3>
             <p className="text-sm text-slate-300">Data-driven marketing plans that hit the target every time.</p>
           </div>
           <div className="bg-slate-800/80 p-6 border-t-4 border-blue-400">
             <div className="w-12 h-12 bg-blue-400/20 flex items-center justify-center rounded mb-4 text-blue-400">
               <Monitor size={24} />
             </div>
             <h3 className="text-xl font-bold text-white mb-2">Development</h3>
             <p className="text-sm text-slate-300">High-performance websites and applications built for scale.</p>
           </div>
           <div className="bg-slate-800/80 p-6 border-t-4 border-red-400">
             <div className="w-12 h-12 bg-red-400/20 flex items-center justify-center rounded mb-4 text-red-400">
               <Users size={24} />
             </div>
             <h3 className="text-xl font-bold text-white mb-2">Social</h3>
             <p className="text-sm text-slate-300">Community management and content creation that engages.</p>
           </div>
        </div>
      </Modal>

      <Modal 
        isOpen={view === ViewState.CONTACT} 
        onClose={() => setView(ViewState.LOBBY)}
        title="Join The Squad"
      >
        <div className="flex flex-col md:flex-row gap-8">
          <div className="flex-1 space-y-6">
            <p className="text-lg">Ready to take your game to the next level? Fill out the form or drop us a direct line.</p>

            <div className="flex items-center gap-4 text-blue-300">
              <Mail />
              <span>hello@levelup-marketing.nl</span>
            </div>
            <div className="flex items-center gap-4 text-blue-300">
              <Phone />
              <span>+31 6 1234 5678</span>
            </div>
          </div>

          <form className="flex-1 space-y-4" onSubmit={(e) => e.preventDefault()}>
            <div className="space-y-2">
              <label className="text-xs font-bold uppercase tracking-wider text-slate-400">Codename (Name)</label>
              <input type="text" className="w-full bg-slate-800 border border-slate-600 p-3 text-white focus:border-blue-500 outline-none transition-colors" placeholder="John Doe" />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-bold uppercase tracking-wider text-slate-400">Comms Frequency (Email)</label>
              <input type="email" className="w-full bg-slate-800 border border-slate-600 p-3 text-white focus:border-blue-500 outline-none transition-colors" placeholder="john@example.com" />
