          className="md:hidden absolute top-[20%] right-10 z-50 bg-white text-blue-600 p-3 rounded-full shadow-[0_0_15px_rgba(59,130,246,0.5)] border-2 border-blue-400 animate-bounce hover:bg-blue-50 transition-colors"
